def gen(rng, size):
    n = max(1, min(size, 100))
    if n == 1:
        return [1, []]
    perm = list(range(n))
    rng.shuffle(perm)
    rank = {node: i for i, node in enumerate(perm)}
    edges = []
    for i in range(n):
        for j in range(n):
            if i != j and rank[i] < rank[j] and rng.random() < 0.3:
                edges.append([i, j])
    return [n, edges]

