class Solution:
    def findChampion(self, n, edges):
        candidates = []
        for i in range(n):
            beaten = False
            for u, v in edges:
                if v == i:
                    beaten = True
                    break
            if not beaten:
                candidates.append(i)
        return candidates[0] if len(candidates) == 1 else -1

