class Solution:
    def findChampion(self, n, edges):
        indeg = [0] * n
        for u, v in edges:
            indeg[v] += 1
        candidates = [i for i in range(n) if indeg[i] == 0]
        return candidates[0] if len(candidates) == 1 else -1

