var findChampion = function(n, edges) {
    const indeg = new Array(n).fill(0);
    for (const [u, v] of edges) {
        indeg[v]++;
    }
    const candidates = [];
    for (let i = 0; i < n; i++) {
        if (indeg[i] === 0) candidates.push(i);
    }
    return candidates.length === 1 ? candidates[0] : -1;
};
